// Diagnostic dump: print the tree-sitter s-expression for a Java fixture.
// Useful when adjusting `extractors/java.rs` against a new grammar version.
//
// Older revs called the C-extern `tree_sitter_java` directly. Modern
// `tree-sitter-java` exposes a `LANGUAGE` constant of type
// `tree_sitter_language::LanguageFn`, which we convert to the
// runtime `tree_sitter::Language` via `Into`. The extern shape no
// longer links — the broken form sat at HEAD as a stale artifact.
fn main() {
    let mut parser = tree_sitter::Parser::new();
    let language: tree_sitter::Language = tree_sitter_java::LANGUAGE.into();
    parser.set_language(&language).expect("set java grammar");
    let source = include_str!("../../tests/fixtures/lambda.java");
    let tree = parser.parse(source, None).expect("parse lambda.java");
    println!("{}", tree.root_node().to_sexp());
}
